+pub fn det_2x2(matrix: [[f64; 2]; 2]) -> Result<f64, LinAlgError> {
+    validate_finite_matrix_2x2(matrix)?;
+    Ok(matrix[0][0] * matrix[1][1] - matrix[0][1] * matrix[1][0])
+}
